PROCEDURE DecomposeTo3NF(Relation R, Set FDs)
BEGIN
 ResultRelations = EMPTY SET

 // Step 1: Find minimal cover of FDs
 MinimalCover = FindMinimalCover(FDs)

 // Step 2: For each FD in minimal cover, create relation
 FOR EACH FD X → Y IN MinimalCover DO
 ResultRelations = ResultRelations ∪ { Relation(X ∪ Y) }
 END FOR

 // Step 3: Ensure one relation contains candidate key
 Keys = FindCandidateKeys(R, FDs)
 IF NOT ANY relation in ResultRelations contains any Key THEN
 RelationWithKey = {}
 FOR EACH attr IN ANY Key DO
 RelationWithKey = RelationWithKey ∪ {attr}
 END FOR
 ResultRelations = ResultRelations ∪ {RelationWithKey}
 END IF

 // Step 4: Remove redundant relations
 ResultRelations = RemoveRedundantRelations(ResultRelations)

 RETURN ResultRelations
END

PROCEDURE FindMinimalCover(Set FDs)
BEGIN
 // Step 1: Split RHS attributes
 SplitFDs = {}
 FOR EACH FD X → Y IN FDs DO
 FOR EACH attribute A IN Y DO
 SplitFDs = SplitFDs ∪ {X → A}
 END FOR
 END FOR

 // Step 2: Remove extraneous LHS attributes
 MinimalFDs = {}
 FOR EACH FD X → A IN SplitFDs DO
 IF |X| > 1 THEN
 FOR EACH attribute B IN X DO
 // Check if B is extraneous
 XminusB = X - {B}
 IF (XminusB)+ contains A THEN
 X = XminusB // Remove B
 END IF
 END FOR
 END IF
 MinimalFDs = MinimalFDs ∪ {X → A}
 END FOR

 // Step 3: Remove redundant FDs
 FinalFDs = {}
 FOR EACH FD X → A IN MinimalFDs DO
 RemainingFDs = MinimalFDs - {X → A}
 IF NOT (X)+ w.r.t RemainingFDs contains A THEN
 FinalFDs = FinalFDs ∪ {X → A}
 END IF
 END FOR

 RETURN FinalFDs
END
